// Filtrar apenas mensagens recebidas de usuários
const body = $input.first().json.body || $input.first().json;

// Validar evento e tipo
if (body.event !== 'message_created') return [];
if (body.message_type !== 'incoming') return [];
if (body.content_type === 'activity') return [];
if (!body.content || body.content.trim() === '') return [];

const conversationId = body.conversation?.id;
const contactName = body.meta?.sender?.name || 'Cliente';
const contactPhone = body.meta?.sender?.phone_number || '';
const messageContent = body.content.trim();
const inboxId = body.inbox_id;
const contactId = body.meta?.sender?.id;

if (!conversationId) return [];

return [{
  json: {
    conversationId,
    contactName,
    contactPhone,
    messageContent,
    inboxId,
    contactId
  }
}];

// Verificar horário de funcionamento (Brasília UTC-3)
// Seg-Sex: 09:00-11:00 e 14:00-16:00
const moment = require('moment');
const d = $input.first().json;

const now = moment().utcOffset(-3);
const dow = now.day(); // 0=Dom, 6=Sab
const t = now.format('HH:mm');

const diasAtivos = [1, 2, 3, 4, 5]; // Seg a Sex
const isDiaAtivo = diasAtivos.includes(dow);

const manha = t >= '09:00' && t <= '11:00';
const tarde = t >= '14:00' && t <= '16:00';
const emHorario = isDiaAtivo && (manha || tarde);

return [{
  json: {
    ...d,
    emHorario,
    horaAtual: t,
    diaAtual: dow
  }
}];

// Montar histórico de mensagens (últimas 10)
const histData = $input.first().json;
const conv = $('Verificar Horário').first().json;

const allMsgs = histData.payload || [];

// Filtrar e converter para formato OpenAI/GROK
const lastMsgs = allMsgs
  .filter(m => m.content && m.content.trim() !== '' && m.message_type !== undefined)
  .slice(-10)
  .map(m => ({
    role: m.message_type === 0 ? 'user' : 'assistant',
    content: m.content.trim()
  }));

// Garantir que a mensagem atual está incluída
const lastMsg = lastMsgs[lastMsgs.length - 1];
if (!lastMsg || lastMsg.content !== conv.messageContent) {
  lastMsgs.push({ role: 'user', content: conv.messageContent });
}

return [{
  json: {
    ...conv,
    messageHistory: lastMsgs
  }
}];

// Processar resposta do GROK e detectar intenção de agendamento
const grokResp = $input.first().json;
const conv = $('Montar Prompt GROK').first().json;

const aiText = grokResp.choices?.[0]?.message?.content || 'Desculpe, não consegui processar sua mensagem. Tente novamente.';

// Detectar intenção de agendamento no formato [AGENDAR]
const agendamentoMatch = aiText.match(/\[AGENDAR\]\s*nome=([^|]+)\|email=([^|]+)\|data=([^|]+)\|hora=([^|]+)\|descricao=([^\n]+)/i);

let agendamento = null;
let textoLimpo = aiText;

if (agendamentoMatch) {
  agendamento = {
    nome: agendamentoMatch[1].trim(),
    email: agendamentoMatch[2].trim(),
    data: agendamentoMatch[3].trim(),
    hora: agendamentoMatch[4].trim(),
    descricao: agendamentoMatch[5].trim()
  };
  // Remover a linha [AGENDAR] do texto que será enviado ao cliente
  textoLimpo = aiText.replace(/\[AGENDAR\][^\n]+\n?/i, '').trim();
}

return [{
  json: {
    ...conv,
    aiResponse: textoLimpo,
    temAgendamento: !!agendamento,
    agendamento
  }
}];
